import{_ as t,o as r,c as a,ag as i}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt1201.jpg",d="/images/lekt1202.jpg",s="/images/lekt1203.jpg",P=JSON.parse('{"title":"Lektion 12","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion12.md","filePath":"lektionen/lektion12.md"}'),u={name:"lektionen/lektion12.md"};function l(b,e,h,o,p,m){return r(),a("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-12" tabindex="-1">Lektion 12 <a class="header-anchor" href="#lektion-12" aria-label="Permalink to &quot;Lektion 12&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>12.1. Partizip Perfekt Passiv (PPP) <ul><li>12.1.1. Schema für transitive Verben</li><li>12.1.2. Schema I für intransitive Verben und Verben der der Bewegung</li><li>12.1.3. Schema II für intransitive Verben und Verben der Bewegung</li></ul></li><li>12.2. Zur Bedeutung des PPP</li><li>12.3. Bildung des PPP <ul><li>12.3.1. PPP auf -ta (kta) <ul><li>12.3.1.1. Ohne Bindevokal -i- (aniṭ)</li><li>12.3.1.2. Mit Bindevokal -i- (seṭ)</li></ul></li></ul></li><li>12.4. Gesetze der Lautverbindung im Wort</li><li>12.5. Wortliste <ul><li>12.5.1. Passiv und PPP der bisher gelernten Wurzeln</li></ul></li><li>12.6. Übung</li></ul><h2 id="_12-1-partizip-perfekt-passiv-ppp" tabindex="-1">12.1. Partizip Perfekt Passiv (PPP) <a class="header-anchor" href="#_12-1-partizip-perfekt-passiv-ppp" aria-label="Permalink to &quot;12.1. Partizip Perfekt Passiv (PPP)&quot;">​</a></h2><p>Eine Möglichkeit, Passivsätze der Vergangenheit zu bilden, ist die Konstruktion mit dem sog. Partizip Perfekt Passiv (PPP).</p><p>In Wirklichkeit ist das PPP kein echtes Partizip, da es nicht von einem Tempusstamm gebildet wird. Es ist vielmehr eine Nominalbildung zur Wurzel mit dem Primärsuffix -ta bzw. -na. Deshalb spricht man in der indischen Grammatik vom Suffix kta.</p><h2 id="_12-1-1-schema-fur-transitive-verben" tabindex="-1">12.1.1. Schema für transitive Verben <a class="header-anchor" href="#_12-1-1-schema-fur-transitive-verben" aria-label="Permalink to &quot;12.1.1. Schema für transitive Verben&quot;">​</a></h2><p>Agens (kartṛ) im Instrumentalis (tṛtīyā) -- direktes Objekt (karman) im Nominativ (prathamā) -- Partizip Perfekt Passiv</p><p>Das PPP stimmt in diesem Fall mit dem Objekt in Zahl, Fall und Geschlecht überein.</p><p>Ein Hilfsverb (&quot;sein&quot;) ist nicht nötig.</p><p>z.B.</p><p>sādhunā svarga āptaḥ = साधुना स्वर्ग आप्तः = &quot;(Vom Heiligen wurde ein Himmel erlangt) = Der Heilige hat einen Himmel erlangt.&quot;</p><p>brāhmaṇena devīṣṭā = ब्राह्मणेन देवीष्टा = &quot;(Vom Brahmanen wurde die Göttin mit einem Opfer verehrt) = Der Brahmane hat die Göttin mit einem Opfer verehrt.&quot;</p><h2 id="_12-1-2-schema-i-fur-intransitive-verben-und-verben-der-der-bewegung" tabindex="-1">12.1.2. Schema I für intransitive Verben und Verben der der Bewegung <a class="header-anchor" href="#_12-1-2-schema-i-fur-intransitive-verben-und-verben-der-der-bewegung" aria-label="Permalink to &quot;12.1.2. Schema I für intransitive Verben und Verben der der Bewegung&quot;">​</a></h2><p>Agens (kartṛ) im Nominativ (prathamā) -- Partizip Perfekt Passiv</p><p>In diesem Fall stimmt das PPP mit dem Agens in Zahl, Fall und Geschlecht überein. Das Partizip Perfekt &quot;Passiv&quot; hat bei intransitiven Verben (Verben ohne direktes Objekt) und Verben der Bewegung aktive Bedeutung.</p><p>z.B.</p><p>kṣatriyā nagaraṃ gatā = क्षत्रिया नगरं गता = &quot;Die Kṣatriyafrau ist in die Stadt gegangen.&quot;</p><h2 id="_12-1-3-schema-ii-fur-intransitive-verben-und-verben-der-bewegung" tabindex="-1">12.1.3. Schema II für intransitive Verben und Verben der Bewegung <a class="header-anchor" href="#_12-1-3-schema-ii-fur-intransitive-verben-und-verben-der-bewegung" aria-label="Permalink to &quot;12.1.3. Schema II für intransitive Verben und Verben der Bewegung&quot;">​</a></h2><p>Agens (kartṛ) im Instrumentalis (tṛtīyā) -- PPP im Nominativ Singular Neutrum</p><p>z.B.</p><p>kṣatriyeṇa (nagaraṃ) gatam = क्षत्रियेण (नगरं) गतम् = &quot;(Vom Kṣatriya wurde (in die Stadt) gegangen) = Der Kṣatriya ist (in die Stadt) gegangen.&quot;</p><p>Die Konstruktion nach Schema II ist viel seltener als die Konstruktion nach Schema I.</p><h2 id="_12-2-zur-bedeutung-des-ppp" tabindex="-1">12.2. Zur Bedeutung des PPP <a class="header-anchor" href="#_12-2-zur-bedeutung-des-ppp" aria-label="Permalink to &quot;12.2. Zur Bedeutung des PPP&quot;">​</a></h2><p>Während also das sog. &quot;Partizip Perfekt Passiv&quot; für transitive Verben in erster Linie passive Bedeutung hat (āpta = &quot;erreicht (worden)&quot;) und für intransitive Verben und Verben der Bewegung aktive Bedeutung (gata = &quot;gegangen&quot;), gibt es einige Verben, bei denen das PPP sowohl aktive als auch passive Bedeutung haben kann:</p><p>z.B.</p><ul><li>gata = गत = &quot;gegangen&quot; (aktiv) ; aber auch: gato mārgaḥ = गतो मार्गः = &quot;ein gegangener Weg&quot; (passiv)</li><li>āpta = आप्त = &quot;erreicht worden&quot; (passiv), &quot;erreicht habend&quot; (aktiv)</li></ul><h2 id="_12-3-bildung-des-ppp" tabindex="-1">12.3. Bildung des PPP <a class="header-anchor" href="#_12-3-bildung-des-ppp" aria-label="Permalink to &quot;12.3. Bildung des PPP&quot;">​</a></h2><p>Es kommen folgende Bildungsweisen vor (zu jeder Wurzel ist jeweils ihr PPP zu lernen!):</p><p>(meist) tiefstufige Wurzel</p><ul><li>+ -ta <ul><li>mit Bindevokal -i- davor: -ita</li><li>ohne Bindevokal: -ta</li></ul></li><li>+ na</li></ul><p>Die Femininstämme lauten: -tā, -itā, -nā; das Neutrum flektiert wie phala n.</p><h3 id="_12-3-1-ppp-auf-ta-kta" tabindex="-1">12.3.1. PPP auf -ta (kta) <a class="header-anchor" href="#_12-3-1-ppp-auf-ta-kta" aria-label="Permalink to &quot;12.3.1. PPP auf -ta (kta)&quot;">​</a></h3><h3 id="_12-3-1-1-ohne-bindevokal-i-anit" tabindex="-1">12.3.1.1. Ohne Bindevokal -i- (aniṭ) <a class="header-anchor" href="#_12-3-1-1-ohne-bindevokal-i-anit" aria-label="Permalink to &quot;12.3.1.1. Ohne Bindevokal -i- (aniṭ)&quot;">​</a></h3><p>aniṭ = &quot;ohne (an-) dem Suffix vorangestelltes (-ṭ) i&quot;</p><p>Ohne Bindevokal bildet man das PPP im Allgemeinen von vokalisch auslautenden Wurzeln sowie vielen anderen Wurzeln, ohne dass man eine Regel dafür angeben könnte, bei wie strukturierten Wurzeln der Bindevokal auftrtitt oder nicht.</p><p>Eine Liste der aniṭ-Wurzeln bei Kielhorn, Grammatik § 298.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>PPP (kta)</th></tr></thead><tbody><tr><td>bhū 1P</td><td></td></tr><tr><td>भू</td><td>bhū-ta</td></tr><tr><td>भूत</td><td></td></tr><tr><td>smṛ 1P</td><td></td></tr><tr><td>स्मृ</td><td>smṛ-ta</td></tr><tr><td>स्मृत</td><td></td></tr><tr><td>nṛt 4P</td><td></td></tr><tr><td>नृत्</td><td>nṛt-ta</td></tr><tr><td>नृत्त</td><td></td></tr><tr><td>nī 1U</td><td></td></tr><tr><td>नी</td><td>nī-ta</td></tr><tr><td>नीत</td><td></td></tr><tr><td>man 4Ā</td><td></td></tr><tr><td>मन्</td><td>ma-ta (*mn-ta)</td></tr><tr><td>मत</td><td></td></tr><tr><td>su 5U</td><td></td></tr><tr><td>सु</td><td>su-ta</td></tr><tr><td>सुत</td><td></td></tr><tr><td>gam 1P</td><td></td></tr><tr><td>गम्</td><td>ga-ta (« *gm-ta)</td></tr><tr><td>गत</td><td></td></tr><tr><td>ji 1P</td><td></td></tr><tr><td>जि</td><td>ji-ta</td></tr><tr><td>जित</td><td></td></tr><tr><td>śru 5P</td><td></td></tr><tr><td>श्रु</td><td>śru-ta</td></tr><tr><td>श्रुत</td><td></td></tr><tr><td>kṛ 8U</td><td></td></tr><tr><td>कृ</td><td>kṛ-ta</td></tr><tr><td>कृत</td><td></td></tr><tr><td>tan 8U</td><td></td></tr><tr><td>तन्</td><td>ta-ta (« *tn-ta)</td></tr><tr><td>तत</td><td></td></tr><tr><td>iṣ 6P</td><td></td></tr><tr><td>इष्</td><td>iṣ-ṭa</td></tr><tr><td>इष्ट</td><td></td></tr></tbody></table></blockquote><h3 id="_12-3-1-2-mit-bindevokal-i-set" tabindex="-1">12.3.1.2. Mit Bindevokal -i- (seṭ) <a class="header-anchor" href="#_12-3-1-2-mit-bindevokal-i-set" aria-label="Permalink to &quot;12.3.1.2. Mit Bindevokal -i- (seṭ)&quot;">​</a></h3><p>seṭ = sa-iṭ = &quot;mit (sa-) dem Suffix vorangestelltem (-ṭ) i&quot;</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>PPP (kta)</th></tr></thead><tbody><tr><td>kup 4P</td><td></td></tr><tr><td>कुप्</td><td>kup-i-ta</td></tr><tr><td>कुपित</td><td></td></tr><tr><td>khād 1P</td><td></td></tr><tr><td>खाद्</td><td>khād-i-ta</td></tr><tr><td>खादित</td><td></td></tr><tr><td>rakṣ 1P</td><td></td></tr><tr><td>रक्ष्</td><td>rakṣ-i-ta</td></tr><tr><td>रक्षित</td><td></td></tr><tr><td>vad 1P</td><td></td></tr><tr><td>वद्</td><td>ud-i-ta (« *vd-i-ta)</td></tr><tr><td>उदित</td><td></td></tr></tbody></table></blockquote><h2 id="_12-4-gesetze-der-lautverbindung-im-wort" tabindex="-1">12.4. Gesetze der Lautverbindung im Wort <a class="header-anchor" href="#_12-4-gesetze-der-lautverbindung-im-wort" aria-label="Permalink to &quot;12.4. Gesetze der Lautverbindung im Wort&quot;">​</a></h2><p>Bei aniṭ-Bildungen sind folgende Gesetze der Lautverbindung im Wort zu beachten. Diese Gesetze sind für das Verständnis der gesamten Sanskrit-Formenlehre sehr wichtig.</p><p>1. k, t, p vor stimmlosem Verschlusslaut (z.B. t, th) bleiben unverändert:</p><blockquote><p>pt, tt, kt = प्त्, त्त्, क्त्</p></blockquote><p>2. ct wird durch kt = क्त् ersetzt:</p><blockquote><p>muc + ta » muk-ta = मुक्त</p></blockquote><p>3. śt wird durch ṣṭ = ष्ट् ersetzt:</p><blockquote><p>dṛś + ti » dṛṣṭi = दृष्टि<br> dṛś + ta » dṛṣṭa =  दृष्ट<br> viś + ta » viṣṭa = विष्ट</p></blockquote><p>4. stimmhafter unaspirierter Verschlusslaut - außer j - wird vor stimmlosem Laut durch den ihm enstprechenden stimmlosen unaspirierten Laut ersetzt:</p><blockquote><p>d + t(h) » tt(h) = त्त्, त्थ् (wichtig für 2. Präsensklasse)</p></blockquote><p>5. jt wird durch kt oder ṣṭ ersetzt (nicht fakultativ!):</p><blockquote><p>yuj + ta » yuk-ta = युक्त<br> yaj + ta » iṣ-ṭa =  इष्ट (« *yj-ta)<br> sṛj + ta » sṛṣ-ṭa = सृष्ट<br> sṛj + ti » sṛṣ-ṭi = सृष्टि</p></blockquote><p>6. Stimmhafter aspirierter Verschlusslaut + stimmloser Verschlusslaut » stimmhafter unaspirierter Verschlusslaut + stimmhafter aspirierter Verschlusslaut (Bartholomaesches Aspiratengesetz:</p><blockquote><p>bh-t » b-dh</p><blockquote><p>labh + ta » lab-dha = लब्ध</p></blockquote><p>dh-t » d-dh</p><blockquote><p>budh + ta » bud-dha = बुद्ध<br> yudh + ta » yud-dha = युद्ध<br> krudh + ta » krud-dha = क्रुद्ध</p></blockquote></blockquote><p>7. h-t wird ersetzt durch ḍh mit Dehnung eines vorhergehenden i bzw. u; oder durch gdh. Vor einem solchen ḍh wird a durch o, seltener durch ā, ersetzt:</p><blockquote><p>dah + ta » dag-dha = दग्ध<br> guh + ta » gūḍha = गूढ (guh 1 (gūhati) &quot;etwas verbergen&quot;)<br> muh + ta » mug-dha / mūḍha = मुग्ध मूढ<br> sah + ta » soḍha = सोढ</p></blockquote><h2 id="_12-5-wortliste" tabindex="-1">12.5. Wortliste <a class="header-anchor" href="#_12-5-wortliste" aria-label="Permalink to &quot;12.5. Wortliste&quot;">​</a></h2><p>budh 4 Ā (budhyate) / 1 U (bodhati), PPP buddha बुध् बुध्यते बोधति बुद्ध : erwachen, zur Erkenntnis erwachen, erkennen; PPP buddha 3 erwacht, daher Buddha = &quot;der Erwachte&quot; (nicht: der Erleuchtete)</p><p><img src="'+n+'" alt=""><br> Abb.: गौतमो बुद्धः<br> Gandhāra (गन्धार), 1./2. Jhdt n. Chr.<br> [Bildquelle: Wikipedia, GNU FDLicense]</p><p>dah 1 P (dahati), PPP dagdha दह् दहति दग्ध : (etwas) verbrennen</p><p>sah 1 Ā (sahate), PPP soḍha सह् सहते सोढ : bewältigen, ertragen, geduldig ertragen = verzeihen</p><p>mṛga m. मृग : Wildtier</p><p>davon:</p><p>mārga m. मार्ग : Weg (Wege waren oft die Wildwechsel)</p><p><img src="'+d+'" alt=""><br> Abb.: मार्गः, Goa (गोंय)<br> [Bildquelle: vm2827. -- <a href="http://www.flickr.com/photos/vm2827/2536957533/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/vm2827/2536957533/</a>. -- Zugriff am 2008-11-30. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz Share alike (Namensnennung)]</p><p>api अपि : auch (nachgestellt)</p><p>Zur 6. Präsensklasse werden von den einheimischen Grammatikern einige Wurzeln gerechnet, die den Präsensstamm mit Nasalinfix und Themavokal a bilden, z.B.:</p><p>muc 6 U (mu-ñ-c-a-ti), PPP mukta मुच् मुञ्चति मुक्त : losmachen, loslassen, befreien; vom Kreislauf der Wiedergeburten (saṃsāra m.) befreien = erlösen</p><p>sic 6 U (si-ñ-c-a-ti), PPP sikta सिच् सिञ्चति सिक्त : beträufeln</p><p>Zur Wortbildung:</p><p>muc: mokṣa m. मोक्ष : Loslösung, Befreiung, Erlösung</p><p>sic + abhi-: abhiṣeka m. अभिषेक : Besprengung eines Königs bei der Königsweihe, Königsweihe</p><p>budh:</p><p>bodhi m./f. बोधि : das Erwachen (wodurch ein Buddha oder Jina zur erlösenden Einsicht gelangt)</p><p><img src="'+s+'" alt=""><br> Abb.: महावीरो जिनः<br> manuskript, Gujarat (ગુજરાત), ca. 1411 n. Chr.<br> [Bildquelle: Wikipedia, Public domain]</p><p>buddhi f. (budh + -ti) बुद्धि : Erkenntnis, Erkenntnisorgan.</p><h3 id="_12-5-1-passiv-und-ppp-der-bisher-gelernten-wurzeln" tabindex="-1">12.5.1. Passiv und PPP der bisher gelernten Wurzeln <a class="header-anchor" href="#_12-5-1-passiv-und-ppp-der-bisher-gelernten-wurzeln" aria-label="Permalink to &quot;12.5.1. Passiv und PPP der bisher gelernten Wurzeln&quot;">​</a></h3><blockquote><p>| Wurzel | Passiv Präsens<br> 3. sg. Indikativ | PPP | | --- | --- | --- | | aś 5Ā<br> अश् | aśyate<br> अश्यते | aṣṭa<br> अष्ट | | āp 5P<br> आप् | āpyate<br> आप्यते | āpta<br> आप्त | | iṣ 6P<br> इष् | iṣyate<br> इष्यते | iṣṭa<br> इष्ट | | kup 4P<br> कुप् | kupyate<br> कुप्यते | kupita<br> कुपित | | kṛ 8U<br> कृ | kriyate<br> क्रियते | kṛta<br> कृत | | kṛṣ 1P, kṛṣ 6U<br> कृष् | kṛṣyate<br> कृष्यते | kṛṣṭa<br> कृष्ट | | krudh 4P<br> क्रुध् | krudhyate<br> क्रुध्यते | kruddha<br> क्रुद्ध | | khād 1P<br> खाद् | khādyate<br> खाद्यते | khādita<br> खादित | | gam 1P<br> गम् | gamyate<br> गम्यते | gata<br> गत | | ji 1P<br> जि | jīyate<br> जीयते | jita<br> जित | | tan 8U<br> तन् | tāyate / tanyate<br> तायते तन्यते | tata<br> तत | | dah 1P<br> दह् | dahyate<br> दह्यते | dagdha<br> दग्ध | | dṛś<br> दृश् | dṛśyate<br> दृश्यते | dṛṣṭa<br> दृष्ट | | nī 1U<br> नी | nīyate<br> नीयते | nīta<br> नीत | | nṛt 4P<br> नृत् | nṛtyate<br> नृत्यते | nṛtta<br> नृत्त | | paś 4P<br> पश् | (dṛśyate)<br> दृश्यते | (dṛṣṭa)<br> दृष्ट | | pracch 6P (eigtl. praś)<br> प्रच्छ् प्रश् | pṛcchyate<br> पृच्छ्यते | pṛṣ-ṭa<br> पृष्ट | | budh 1U, 4Ā<br> बुध् | budhyate<br> बुध्यते | buddha<br> बुद्ध | | bhū 1P<br> भू | bhūyate<br> भूयते | bhūta<br> भूत | | man 4Ā<br> मन् | manyate<br> मन्यते | mata<br> मत | | muc 6U<br> मुच् | mucyate<br> मुच्यते | mukta<br> मुक्त | | muh 4P<br> मुह् | muhyate<br> मुह्यते | mugdha / mūḍha<br> मुग्ध मूढ | | yaj 1U<br> यज् | ijyate<br> इज्यते | iṣṭa<br> इष्ट | | yudh 4Ā<br> युध् | yudhyate<br> युध्यते | yuddha<br> युद्ध | | rakṣ 1P<br> रक्ष् | rakṣyate<br> रक्ष्यते | rakṣita<br> रक्षित | | labh 1Ā<br> लभ् | labhyate<br> लभ्यते | labdha<br> लब्ध | | lubh 4P<br> लुभ् | lubhyate<br> लुभ्यते | lubdha<br> लुब्ध | | vad 1P<br> वद् | udyate<br> उद्यते | udita<br> उदित | | viś 6P<br> विश् | viśyate<br> विश्यते | viṣṭa<br> विष्ट | | śru 5P<br> श्रु | śrūyate<br> श्रूयते | śruta<br> श्रुत | | sah 1Ā<br> सह् | sahyate<br> सह्यते | soḍha<br> सोढ | | sic 6U<br> सिच् | sicyate<br> सिच्यते | sikta<br> सिक्त | | su 5U<br> सु | sūyate<br> सूयते | suta<br> सुत | | sṛj 6P<br> सृज् | sṛjyate<br> सृज्यते | sṛṣṭa<br> सृष्ट | | smṛ 1P<br> स्मृ | smaryate<br> स्मर्यते | smṛta<br> स्मृत |</p></blockquote><h2 id="_12-6-ubung" tabindex="-1">12.6. Übung <a class="header-anchor" href="#_12-6-ubung" aria-label="Permalink to &quot;12.6. Übung&quot;">​</a></h2><p>A) Bilden Sie aus den Aktivsätzen von <a href="./lektion07">Lektion 7</a>, Übung A mit dem PPP Passivsätze der Vergangenheit, bei intransitiven Verben und Verben der Bewegung Aktivsätze der Vergangenheit.</p><p>B) Bilden Sie die entsprechenden PPPs zu den Verbformen von <a href="./lektion10">Lektion 10</a>, Übung A. Beachten Sie dabei, dass einer Form wie sṛjati PPPs in allen drei Geschlechtern entsprechen.</p><p>C) Setzen Sie die Sätze von <a href="./lektion10">Lektion 10</a>, Übung C passiv in die Vergangenheit.</p>',86)])])}const k=t(u,[["render",l]]);export{P as __pageData,k as default};
